mapper.select:
SELECT id, user_id, sku_id, quantity, selected, create_time, update_time
FROM cart_item
WHERE user_id = #{userId}
  AND sku_id = #{skuId}

mapper.update:
UPDATE cart_item
SET quantity = #{quantity},
    selected = #{selected}
WHERE id = #{id}

